variable "do_token" {
  description = "DigitalOcean API token (read/write)"
  type        = string
  sensitive   = true
}

variable "ssh_key_name" {
  description = "Name of an existing SSH key already uploaded to DigitalOcean"
  type        = string
  default     = "m5" # matches ~/.ssh/id_ed25519 (dpaluy@users.noreply.github.com)
}

variable "admin_ip" {
  description = "CIDR allowed SSH access. Restrict to your IP in real production; 0.0.0.0/0 relies on fail2ban only."
  type        = string
  default     = "0.0.0.0/0"
}

variable "droplet_region" {
  description = "DigitalOcean region slug"
  type        = string
  default     = "nyc3"
}

variable "droplet_size" {
  description = "Droplet size slug"
  type        = string
  default     = "s-2vcpu-4gb"
}

variable "project_name" {
  description = "Used for resource naming and tags"
  type        = string
  default     = "reviewlens"
}

variable "spaces_region" {
  description = "DO Spaces region"
  type        = string
  default     = "nyc3"
}

variable "spaces_bucket" {
  description = "Name of the DO Spaces bucket (created in DO Console) for pg_dump backups"
  type        = string
  default     = "reviewlens-spaces"
}

# Spaces credentials for the bucket resource. Created in the DO Console and
# stored in 1Password (the Spaces API cannot issue bucket-creation rights,
# so the key must be created manually once). Loaded by infra/bin/provision.
variable "spaces_access_id" {
  description = "DO Spaces access key id (from 1Password)"
  type        = string
  default     = ""
  sensitive   = true
}

variable "spaces_secret_key" {
  description = "DO Spaces secret key (from 1Password)"
  type        = string
  default     = ""
  sensitive   = true
}

arguments.command:
set -euo pipefail
OP_ACCOUNT=${OP_ACCOUNT:-HOPQBD5OXZDG7M6WBMJPF6RKRI}
export OP_ACCOUNT
export REVIEW_LENS_DATABASE_PASSWORD_VALUE="$(op read 'op://reviewlens/production-postgres/password' --account "$OP_ACCOUNT")"
export ACTIVE_STORAGE_ACCESS_KEY_ID_VALUE="$(op read 'op://reviewlens/digitalocean-spaces/access_key_id' --account "$OP_ACCOUNT")"
export ACTIVE_STORAGE_SECRET_ACCESS_KEY_VALUE="$(op read 'op://reviewlens/digitalocean-spaces/secret_access_key' --account "$OP_ACCOUNT")"
export OPEN_AI_API_KEY_VALUE="${OPENAI_API_KEY:-}"

bin/rails runner <<'RUBY'
require "yaml"

updates = {
  "REVIEW_LENS_DATABASE_PASSWORD" => ENV.fetch("REVIEW_LENS_DATABASE_PASSWORD_VALUE"),
  "active_storage" => {
    "digitalocean_spaces" => {
      "service" => "S3",
      "access_key_id" => ENV.fetch("ACTIVE_STORAGE_ACCESS_KEY_ID_VALUE"),
      "secret_access_key" => ENV.fetch("ACTIVE_STORAGE_SECRET_ACCESS_KEY_VALUE"),
      "region" => "nyc3",
      "bucket" => "reviewlens-spaces",
      "endpoint" => "https://nyc3.digitaloceanspaces.com"
    }
  },
  "open_ai" => {
    "api_key" => ENV["OPEN_AI_API_KEY_VALUE"].presence
  }
}

credentials = [
  [ Rails.root.join("config/credentials.yml.enc"), Rails.root.join("config/master.key") ],
  [ Rails.root.join("config/credentials/production.yml.enc"), Rails.root.join("config/credentials/production.key") ]
]

credentials.each do |config_path, key_path|
  config = ActiveSupport::EncryptedConfiguration.new(
    config_path: config_path,
    key_path: key_path,
    env_key: "RAILS_MASTER_KEY",
    raise_if_missing_key: true
  )

  data = YAML.safe_load(config.read, aliases: true) || {}
  data.merge!(updates) { |_key, _old, new_value| new_value }
  config.write(data.to_yaml)
end
RUBY

